def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 2, -2):
                for b in range(1, a + 5):
                    term1 = np.tanh((ratio - a) ** 4 / (a * b + 1))
                    term2 = np.sin(ratio * b / (a + 2))
                    priority += term1 * term2 * ((a + b) % 3 - 1)
            priority += np.exp(ratio - 8) * np.cos(ratio * 1.3) ** 2.2
            if bin_cap < item * 0.5:
                priority += np.log1p(item * bin_cap) * 7.7
            else:
                priority -= np.exp(-0.5 * ratio) * 3.3
        elif 5 < ratio <= 8:
            partial = 0
            for x in range(2, int(np.ceil(ratio)) + 4):
                for y in range(1, x + 4):
                    val = ((ratio - x) ** 2.5) * np.cos(ratio * y / (x + 0.5)) / (y + 1.5)
                    partial += np.tanh(val) * 1.9
            priority = partial + np.log(ratio) * 6 - np.tanh(ratio - 5) * 2.5
            for z in range(1, 6):
                priority += (ratio / (z + 0.7)) * np.sin(z * ratio * 0.9) * (i % (z + 1) + 0.2)
        elif 2 <= ratio <= 5:
            s = 0
            for m in range(1, 15):
                part = ((ratio - 2) ** m) / (m * 2.1) * np.cos(m * ratio * 1.1)
                s += part * (-1) ** m
            priority = (s * np.sin(5 * ratio)) + np.log(ratio + 1) * 5 - np.tanh(3 * (5 - ratio)) * 1.8
            if bin_cap < item:
                priority += np.sqrt(item / (bin_cap + 1)) * 3
            else:
                priority -= np.cos(10 * ratio) * 2
        elif 1 <= ratio < 2:
            s1 = 0
            for n in range(1, 12):
                s1 += ((2 - ratio) ** n) / (n ** 2 + 1.2) * np.cos(n * ratio * 1.4)
            s2 = 0
            for k in range(1, 7):
                s2 += np.sin(k * ratio * i) * ((ratio - 1) ** k) / (k + 0.5)
            priority = s1 + s2 + np.exp(-2 / (ratio + 0.1))
            if bin_cap < item * 0.9:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 1.5) * 2.5
        elif 0.5 <= ratio < 1:
            s = 0
            for p in range(1, 18):
                s += ((1 - ratio) ** p) / (p * 3.5) * np.sin(p * item * 1.3)
            priority = s
            if (i + int(item * 2)) % 5 == 1:
                priority *= np.log1p(bin_cap + 2) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1)
            for q in range(1, 8):
                priority += ((1 - ratio) ** q) * np.cos(q * ratio * 2.1) * 0.85
        elif 0.15 <= ratio < 0.5:
            s = 0
            for r in range(1, 20):
                val = ((0.5 - ratio) ** r) / (r * 3) * np.cos(r * ratio * 3)
                s += val * (-1) ** (r + 1)
            priority = s + 2 / (bin_cap + 2)
            if int(item * 2.2) % 6 < 3:
                priority *= 2
            else:
                priority /= 2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 3
            else:
                priority -= np.exp(-ratio * 2.5) * 2.8
            for s_idx in range(1, 10):
                priority += ((0.5 - ratio) ** s_idx) / (s_idx * 8) * np.sin(item * s_idx * 1.5)
        else:
            s = 0
            for t in range(1, 15):
                s += ((0.15 - ratio) ** t) / (t * 10) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 3)
            if int(item * 0.8) % 7 < 4:
                priority *= 2.5
            else:
                priority /= 2.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 4.2
            else:
                priority -= np.exp(-ratio * 3) * 3.7
            for u in range(1, 12):
                priority += ((0.15 - ratio) ** u) / (u * 9) * np.cos(item * u * 1.05)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.2
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            sign = 1 if (i + idx) % 4 == 1 else -1
            if sign == 1:
                priority += np.sin(ratio * (i + idx) * 1.15) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.15) * 0.4
        if i % 4 == 1:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i + int(item * 1.2)) % 5 == 0:
            for v in range(1, 4):
                priority += np.cos(ratio * v * i) * v * 0.2
        else:
            for w in range(1, 4):
                priority -= np.sin(ratio * w * i) * w * 0.25
        priorities[i] = priority
    return priorities
